#include <iostream>
#include <sstream>
#include <string>
#include <vector>

class Solution {
public:
    std::string discountPrices(std::string sentence, int discount) {
        std::istringstream iss(sentence);
        std::string word;
        std::vector<std::string> prices;

        while (iss >> word) {
            prices.push_back(word);
        }

        std::string result = "";
        for (int i = 0; i < prices.size(); i++) {
            double price = std::stod(prices[i]);
            double discounted_price = price * (1 - (double)discount / 100.0);
            result += std::fixed << std::setprecision(2) << discounted_price << ' ';
        }

        return result;
    }
};
```

